oxy_webhelp_navlinks = {"oracle_databases_rsc-d30753e31699":{"topics":[{"title":"Rubrik Backup Service for Oracle","shortdesc":"<p class=\"shortdesc\">Rubrik Backup Service is required in order to perform automated discovery of Oracle         hosts, Oracle RAC systems, and Oracle databases.<\/p>","href":"rbs\/oracle_rbs.html","attributes":{"data-id":"oracle_rbs"},"menu":{"hasChildren":false},"tocID":"oracle_rbs-d30753e31713","next":"oracle_rbs-d30753e31713"},{"title":"Oracle configuration","shortdesc":"<p class=\"shortdesc\">Initial configuration of the Rubrik cluster for Oracle requires at least one open or     mounted Oracle database and a user account with SYSDBA privileges.<\/p>","href":"oracle\/oracle_config.html","attributes":{"data-id":"config_prereqs"},"menu":{"hasChildren":false},"tocID":"config_prereqs-d30753e31735","next":"config_prereqs-d30753e31735"},{"title":"Role based access","shortdesc":"<p class=\"shortdesc\">Rubrik provides role-based access control, along with options for integrating with         existing directory services.<\/p>","href":"oracle\/role_based_access.html","attributes":{"data-id":"role_based_access"},"menu":{"hasChildren":false},"tocID":"role_based_access-d30753e31902","next":"role_based_access-d30753e31902"},{"title":"Oracle SEPS wallet","shortdesc":"<p class=\"shortdesc\">The Oracle Secure External Password Store wallet feature provides additional security         for connections by not exposing your username and password on the command line when you log         in. The feature stores the password credentials in the client-side Oracle         wallet.<\/p>","href":"oracle\/oracle_seps_wallet.html","attributes":{"data-id":"oracle_seps_wallet"},"menu":{"hasChildren":false},"tocID":"oracle_seps_wallet-d30753e31968","next":"oracle_seps_wallet-d30753e31968"},{"title":"Oracle database management","shortdesc":"<p class=\"shortdesc\">Manage discovered Oracle hosts and Oracle RAC systems from the Rubrik Oracle         Databases page. <\/p>","href":"oracle\/rbk_oracle_database_management.html","attributes":{"data-id":"rbk_oracle_database_management"},"menu":{"hasChildren":false},"tocID":"rbk_oracle_database_management-d30753e32001","next":"rbk_oracle_database_management-d30753e32001"},{"title":"Export Oracle database logs to a USB device","shortdesc":"<p class=\"shortdesc\">You can use Rubrik REST APIs to export logs from multiple Oracle databases to USB         devices.<\/p>","href":"oracle\/export_database_logs_usb.html","attributes":{"data-id":"export_database_logs_usb"},"menu":{"hasChildren":false},"tocID":"export_database_logs_usb-d30753e32183","next":"export_database_logs_usb-d30753e32183"},{"title":"Oracle Data Guard on Rubrik clusters","shortdesc":"<p class=\"shortdesc\">Rubrik clusters support Oracle Data Guard configurations to back up primary and         standby databases and to discover new Data Guard groups.<\/p>","href":"oracle\/oracle_data_guard_rubrik_clusters.html","attributes":{"data-id":"oracle_data_guard_rubrik_clusters"},"menu":{"hasChildren":false},"tocID":"oracle_data_guard_rubrik_clusters-d30753e32238","next":"oracle_data_guard_rubrik_clusters-d30753e32238"},{"title":"Backups and archived redo logs","shortdesc":"<p class=\"shortdesc\">The Rubrik cluster protects Oracle databases with database backups and archived redo     log backups. These jobs run separately and at different frequencies.<\/p>","href":"oracle\/backups_arch_redo_logs.html","attributes":{"data-id":"backups_arch_redo_logs"},"menu":{"hasChildren":false},"tocID":"backups_arch_redo_logs-d30753e32462","next":"backups_arch_redo_logs-d30753e32462"},{"title":"Archive log restore","shortdesc":"<p class=\"shortdesc\">Archive log restore reinstates archived logs from a specified time range or log         sequence period.<\/p>","href":"oracle\/archive_log_restoration.html","attributes":{"data-id":"archive_log_restoration"},"menu":{"hasChildren":false},"tocID":"archive_log_restoration-d30753e32561","next":"archive_log_restoration-d30753e32561"},{"title":"Oracle pluggable databases","shortdesc":"<p class=\"shortdesc\">You can restore, mount, and clone Oracle pluggable databases on the Rubrik         cluster.<\/p>","href":"oracle\/oracle_pluggable_databases.html","attributes":{"data-id":"oracle_pluggable_databases"},"menu":{"hasChildren":false},"tocID":"oracle_pluggable_databases-d30753e32594","next":"oracle_pluggable_databases-d30753e32594"},{"title":"Taking an on-demand snapshot","shortdesc":"<p class=\"shortdesc\">Manually initiate a database snapshot in addition to the policy-based snapshots of         the database. Assign an SLA Domain to manage that snapshot.<\/p>","href":"oracle\/rbk_taking_an_on_demand_snapshot.html","attributes":{"data-id":"rbk_taking_an_on_demand_snapshot"},"menu":{"hasChildren":false},"tocID":"rbk_taking_an_on_demand_snapshot-d30753e32652","next":"rbk_taking_an_on_demand_snapshot-d30753e32652"},{"title":"Recover Oracle databases","shortdesc":"<p class=\"shortdesc\">Provides a summary of the methods available in <span class=\"ph\">RSC<\/span> for recovering         Oracle databases.<\/p>","href":"oracle\/recover_oracle_databases.html","attributes":{"data-id":"recover_oracle_databases"},"menu":{"hasChildren":false},"tocID":"recover_oracle_databases-d30753e32674","next":"recover_oracle_databases-d30753e32674"}]}};